function executeSkill(context) {
  const battle = context.battle;
  const cardPool = ['sample-active-card', 'sample-reactive-card'];
  battle.players.forEach(function(player) {
    for (let i = 0; i < 3; i++) {
      const randomCard = cardPool[Math.floor(Math.random() * cardPool.length)];
      addCardToHand(randomCard, player.playerId);
    }
  });
  return { success: true, message: '所有玩家抽了3张初始手牌' };
}
